// This is a comment — JavaScript ignores it
// Comments help humans understand code

// console.log prints text to the developer console
console.log('Hello, World!');
// Expected output: Hello, World!

// You can also print numbers
console.log(42);
// Expected output: 42

// Multiple values can be printed at once
console.log('Hello', 'World', '!');
// Expected output: Hello World !
